__kernel void srad_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global int* iN,
    __global int* iS,
    __global int* jE,
    __global int* jW,
    __global float* dN,
    __global float* dS,
    __global float* dW,
    __global float* dE,
    __global float* c,
    const float q0sqr,
    __global float* J)
{
    int gid = get_global_id(0);
    if (gid >= Ne) return;

    int i = gid / Nc;
    int j = gid % Nc;

    float Jc = J[gid];

    // Compute directional derivatives
    dN[gid] = J[iN[i] * Nc + j] - Jc;
    dS[gid] = J[iS[i] * Nc + j] - Jc;
    dW[gid] = J[i * Nc + jW[j]] - Jc;
    dE[gid] = J[i * Nc + jE[j]] - Jc;

    float G2 = (dN[gid]*dN[gid] + dS[gid]*dS[gid] + dW[gid]*dW[gid] + dE[gid]*dE[gid]) / (Jc*Jc);

    float L = (dN[gid] + dS[gid] + dW[gid] + dE[gid]) / Jc;

    float num = (0.5f*G2) - ((1.0f/16.0f)*(L*L));
    float den = 1.0f + (0.25f*L);
    float qsqr = num/(den*den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f+q0sqr));
    c[gid] = 1.0f / (1.0f + den);

    if (c[gid] < 0.0f) c[gid] = 0.0f;
    else if (c[gid] > 1.0f) c[gid] = 1.0f;
}

__kernel void srad2_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global int* iN,
    __global int* iS,
    __global int* jE,
    __global int* jW,
    __global float* dN,
    __global float* dS,
    __global float* dW,
    __global float* dE,
    __global float* c,
    __global float* J)
{
    int gid = get_global_id(0);
    if (gid >= Ne) return;

    int i = gid / Nc;
    int j = gid % Nc;

    float cN = c[gid];
    float cS = c[iS[i] * Nc + j];
    float cW = c[gid];
    float cE = c[i * Nc + jE[j]];

    float D = cN * dN[gid] + cS * dS[gid] + cW * dW[gid] + cE * dE[gid];

    J[gid] = J[gid] + 0.25f * lambda * D;
}
